/* The main list, rebuilt each frame: grouped = one entry per console, flat = one
 * entry per repo. */
static MenuRef g_menu[MAX_CONSOLES * MAX_REPOS];

static int build_menu(void) {
    int cap = (int)(sizeof(g_menu) / sizeof(g_menu[0]));
    int n = 0;
    if (g_prefs.group_consoles) {
        for (int c = 0; c < g_cfg.console_count && n < cap; c++) {
            g_menu[n].ci = c;
            g_menu[n].ri = -1;
            n++;
        }
    } else {
        for (int c = 0; c < g_cfg.console_count; c++) {
            for (int r = 0; r < g_cfg.consoles[c].repo_count && n < cap; r++) {
                g_menu[n].ci = c;
                g_menu[n].ri = r;
                n++;
            }
        }
    }
    return n;
}

static void draw_menu(int cursor, int top, int rows, int n) {
    char sub[48];
    snprintf(sub, sizeof(sub), "%s  (%d/%d)",
             g_prefs.group_consoles ? "Consoles" : "Repos", n > 0 ? cursor + 1 : 0,
             n);
    draw_header(sub);

    if (n == 0) {
        printf(C_CYAN
               "  No collections yet. Press Y to add one\n"
               "  (you provide the archive.org item id)." C_RESET "\n");
    }
    int W = con_width();
    for (int i = top; i < n && i < top + rows; i++) {
        bool sel = (i == cursor);
        ConsoleGroup *g = &g_cfg.consoles[g_menu[i].ci];
        if (g_menu[i].ri < 0) {
            /* grouped: one row per console */
            if (sel) {
                char line[96];
                snprintf(line, sizeof(line), "> %-16.16s (%d repos)", g->console,
                         g->repo_count);
                hl_row(line);
            } else {
                printf("  %s%-16.16s%s %s(%d repos)%s\n", C_WHITE, g->console,
                       C_RESET, C_CYAN, g->repo_count, C_RESET);
            }
        } else {
            /* flat: one row per repo, "target - label" */
            Repo *rp = &g->repos[g_menu[i].ri];
            char name[96];
            snprintf(name, sizeof(name), "%s - %s", g->target, rp->label);
            if (sel) {
                char line[128];
                snprintf(line, sizeof(line), "> [%-3s] %-*.*s",
                         rp->enabled ? "on" : "off", W - 9, W - 9, name);
                hl_row(line);
            } else {
                printf("  %s[%-3s]%s %s%-*.*s%s\n", rp->enabled ? C_GREEN : "",
                       rp->enabled ? "on" : "off", C_RESET, C_WHITE, W - 9,
                       W - 9, name, C_RESET);
            }
        }
    }
    draw_scrollbar(top, n);
    if (g_prefs.group_consoles) {
        draw_footer("A open  Y add repo  - del console  ZL queue  R installed  "
                    "L settings  ZR help  +exit");
    } else {
        draw_footer("A browse  X edit  Y add repo  - del repo  ZL queue  "
                    "R install  L settings  ZR help  +exit");
    }
    consoleUpdate(NULL);
}

/* Add a repo: pick a supported console, then enter its label + archive id. */
static void add_repo_flow(void) {
    const char *cname = pick_console();
    if (!cname) {
        return;
    }
    char lbl[64] = {0}, id[256] = {0};
    if (prompt_text("Repo name (e.g. No-Intro)", NULL, lbl, sizeof(lbl)) &&
        prompt_text("archive.org item id", NULL, id, sizeof(id))) {
        ConsoleGroup *g = config_add_console(&g_cfg, cname);
        if (g && config_add_repo(g, lbl, id)) {
            config_sort(&g_cfg); /* keep the console list A-Z */
            config_save(&g_cfg);
            toast("Added %.30s to %s", lbl, cname);
        } else {
            toast_error("Couldn't add repo (full?)");
        }
    }
}

int main(int argc, char **argv) {
    /* hbloader passes our own .nro path as argv[0]; fall back to the default. */
    if (argc > 0 && argv[0] && strstr(argv[0], ".nro")) {
        snprintf(g_self_path, sizeof(g_self_path), "%s", argv[0]);
    } else {
        snprintf(g_self_path, sizeof(g_self_path), "%s", DEFAULT_SELF_PATH);
    }

    consoleInit(NULL);
    padConfigureInput(1, HidNpadStyleSet_NpadStandard);
    padInitializeDefault(&g_pad);
    romfsInit();
    psmInitialize(); /* battery readout in the header (best-effort) */

    if (!net_init()) {
        printf("Network init failed.\n");
        consoleUpdate(NULL);
    }

    config_load(&g_cfg);
    config_sort(&g_cfg);
    creds_load(&g_creds);
    prefs_load(&g_prefs);
    queue_init();

    int cursor = 0;
    int top = 0;
    int hold = 0;
    const int rows = list_rows();

    while (appletMainLoop()) {
        int n = build_menu();
        if (cursor >= n) {
            cursor = n > 0 ? n - 1 : 0;
        }
        if (cursor < top) {
            top = cursor;
        }
        if (cursor >= top + rows) {
            top = cursor - rows + 1;
        }
        draw_menu(cursor, top, rows, n);
        applet_sleep_tick();

        padUpdate(&g_pad);
        u64 k = padGetButtonsDown(&g_pad);
        u64 kh = padGetButtons(&g_pad);

        if (k & HidNpadButton_Plus) {
            break;
        }
        if (k & HidNpadButton_ZL) {
            view_queue();
            continue;
        }
        if (k & HidNpadButton_ZR) {
            show_help();
            continue;
        }
        if (k & HidNpadButton_L) {
            edit_settings();
            continue;
        }
        if (k & HidNpadButton_R) {
            view_installed();
            continue;
        }
        if (k & HidNpadButton_Y) {
            add_repo_flow(); /* pick a supported console, then add a repo */
            continue;
        }

        if (n == 0) {
            continue;
        }
        int d = nav_repeat(k, kh, &hold);
        if (d < 0) {
            cursor = (cursor - 1 + n) % n;
        }
        if (d > 0) {
            cursor = (cursor + 1) % n;
        }
        MenuRef ref = g_menu[cursor];
        if (k & HidNpadButton_A) {
            if (ref.ri < 0) {
                open_console(ref.ci); /* grouped: show this console's repos */
            } else {
                browse_repo_refs(g_menu, n, cursor); /* flat: browse this repo */
            }
        }
        if ((k & HidNpadButton_X) && !g_prefs.group_consoles) {
            repo_editor(ref.ci, ref.ri); /* flat: edit the selected repo */
        }
        if (k & HidNpadButton_Minus) {
            if (g_prefs.group_consoles) {
                char msg[96];
                snprintf(msg, sizeof(msg),
                         "Delete console '%s' and all its repos?",
                         g_cfg.consoles[ref.ci].console);
                if (confirm_danger(msg, "This cannot be undone.")) {
                    config_remove_console(&g_cfg, ref.ci);
                    config_save(&g_cfg);
                    toast("Deleted console");
                }
            } else {
                if (confirm_danger("Delete this repo?",
                                   "This cannot be undone.")) {
                    config_remove_repo(&g_cfg.consoles[ref.ci], ref.ri);
                    config_save(&g_cfg);
                    toast("Deleted repo");
                }
            }
        }
    }

    queue_exit();
    appletSetMediaPlaybackState(false);
    net_exit();
    psmExit();
    romfsExit();
    consoleExit(NULL);
    return 0;
}
